begin;
create extension if not exists "pgcrypto";
create type public.app_role as enum ('owner','admin','team_member','client','client_viewer');
create type public.lead_status as enum ('new','qualified','discovery_booked','proposal_sent','negotiating','won','lost');
create type public.project_status as enum ('planning','active','paused','review','launched','archived');
create type public.item_status as enum ('not_started','in_progress','blocked','in_review','approved','completed');
create type public.invoice_status as enum ('draft','open','paid','overdue','void');

create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text,avatar_url text,role public.app_role not null default 'client',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.organizations(id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,website text,primary_contact_id uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.organization_members(organization_id uuid not null references public.organizations(id) on delete cascade,user_id uuid not null references public.profiles(id) on delete cascade,role public.app_role not null default 'client',created_at timestamptz not null default now(),primary key(organization_id,user_id));
create table public.leads(id uuid primary key default gen_random_uuid(),name text not null,email text not null,company text,phone text,project_type text not null,budget_range text not null,timeline text,message text not null,source text not null default 'website',status public.lead_status not null default 'new',estimated_value numeric(12,2),assigned_to uuid references public.profiles(id) on delete set null,next_follow_up_at timestamptz,internal_notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.lead_activities(id uuid primary key default gen_random_uuid(),lead_id uuid not null references public.leads(id) on delete cascade,actor_id uuid references public.profiles(id) on delete set null,activity_type text not null,body text,created_at timestamptz not null default now());
create table public.projects(id uuid primary key default gen_random_uuid(),organization_id uuid references public.organizations(id) on delete set null,name text not null,slug text not null unique,description text,status public.project_status not null default 'planning',progress integer not null default 0 check(progress between 0 and 100),budget numeric(12,2),start_date date,target_launch_date date,launched_at timestamptz,created_by uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.project_members(project_id uuid not null references public.projects(id) on delete cascade,user_id uuid not null references public.profiles(id) on delete cascade,role public.app_role not null default 'client',created_at timestamptz not null default now(),primary key(project_id,user_id));
create table public.project_phases(id uuid primary key default gen_random_uuid(),project_id uuid not null references public.projects(id) on delete cascade,name text not null,description text,status public.item_status not null default 'not_started',position integer not null default 0,start_date date,due_date date,created_at timestamptz not null default now());
create table public.milestones(id uuid primary key default gen_random_uuid(),project_id uuid not null references public.projects(id) on delete cascade,phase_id uuid references public.project_phases(id) on delete set null,title text not null,description text,status public.item_status not null default 'not_started',due_date date,requires_approval boolean not null default false,approved_at timestamptz,approved_by uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.tasks(id uuid primary key default gen_random_uuid(),project_id uuid not null references public.projects(id) on delete cascade,milestone_id uuid references public.milestones(id) on delete set null,title text not null,description text,status public.item_status not null default 'not_started',assigned_to uuid references public.profiles(id) on delete set null,due_date date,client_visible boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.files(id uuid primary key default gen_random_uuid(),organization_id uuid references public.organizations(id) on delete cascade,project_id uuid references public.projects(id) on delete cascade,uploaded_by uuid references public.profiles(id) on delete set null,bucket text not null default 'project-files',storage_path text not null unique,file_name text not null,mime_type text,size_bytes bigint,folder text,client_visible boolean not null default true,created_at timestamptz not null default now());
create table public.messages(id uuid primary key default gen_random_uuid(),project_id uuid not null references public.projects(id) on delete cascade,sender_id uuid references public.profiles(id) on delete set null,body text not null,parent_id uuid references public.messages(id) on delete cascade,created_at timestamptz not null default now(),edited_at timestamptz);
create table public.approvals(id uuid primary key default gen_random_uuid(),project_id uuid not null references public.projects(id) on delete cascade,milestone_id uuid references public.milestones(id) on delete cascade,title text not null,description text,status public.item_status not null default 'in_review',requested_by uuid references public.profiles(id) on delete set null,decided_by uuid references public.profiles(id) on delete set null,decision_note text,decided_at timestamptz,created_at timestamptz not null default now());
create table public.proposals(id uuid primary key default gen_random_uuid(),organization_id uuid references public.organizations(id) on delete set null,lead_id uuid references public.leads(id) on delete set null,project_id uuid references public.projects(id) on delete set null,title text not null,status text not null default 'draft',subtotal numeric(12,2) not null default 0,tax numeric(12,2) not null default 0,total numeric(12,2) not null default 0,currency text not null default 'CAD',public_token uuid not null default gen_random_uuid() unique,expires_at timestamptz,accepted_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.proposal_items(id uuid primary key default gen_random_uuid(),proposal_id uuid not null references public.proposals(id) on delete cascade,title text not null,description text,quantity numeric(10,2) not null default 1,unit_price numeric(12,2) not null default 0,optional boolean not null default false,selected boolean not null default true,position integer not null default 0);
create table public.invoices(id uuid primary key default gen_random_uuid(),organization_id uuid references public.organizations(id) on delete set null,project_id uuid references public.projects(id) on delete set null,proposal_id uuid references public.proposals(id) on delete set null,invoice_number text not null unique,status public.invoice_status not null default 'draft',amount_due numeric(12,2) not null default 0,amount_paid numeric(12,2) not null default 0,currency text not null default 'CAD',issued_at timestamptz,due_at timestamptz,paid_at timestamptz,stripe_invoice_id text unique,created_at timestamptz not null default now());
create table public.payments(id uuid primary key default gen_random_uuid(),invoice_id uuid references public.invoices(id) on delete set null,project_id uuid references public.projects(id) on delete set null,amount numeric(12,2) not null,currency text not null default 'CAD',provider text not null default 'stripe',provider_payment_id text unique,status text not null,paid_at timestamptz,created_at timestamptz not null default now());
create table public.notifications(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles(id) on delete cascade,title text not null,body text,href text,read_at timestamptz,created_at timestamptz not null default now());
create table public.services(id uuid primary key default gen_random_uuid(),slug text not null unique,title text not null,summary text not null,body jsonb not null default '{}'::jsonb,position integer not null default 0,published boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.case_studies(id uuid primary key default gen_random_uuid(),slug text not null unique,title text not null,category text,summary text not null,challenge text,approach text,outcome text,cover_image text,content jsonb not null default '{}'::jsonb,featured boolean not null default false,published boolean not null default false,published_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.testimonials(id uuid primary key default gen_random_uuid(),client_name text not null,company text,quote text not null,project_id uuid references public.projects(id) on delete set null,published boolean not null default false,position integer not null default 0,created_at timestamptz not null default now());
create table public.blog_posts(id uuid primary key default gen_random_uuid(),slug text not null unique,title text not null,excerpt text,content jsonb not null default '{}'::jsonb,cover_image text,author_id uuid references public.profiles(id) on delete set null,published boolean not null default false,published_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.activity_logs(id uuid primary key default gen_random_uuid(),actor_id uuid references public.profiles(id) on delete set null,organization_id uuid references public.organizations(id) on delete cascade,project_id uuid references public.projects(id) on delete cascade,action text not null,entity_type text,entity_id uuid,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());

create or replace function public.set_updated_at() returns trigger language plpgsql as $$begin new.updated_at=now();return new;end;$$;
do $$declare r record;begin for r in select table_name from information_schema.columns where table_schema='public' and column_name='updated_at' loop execute format('create trigger %I_set_updated_at before update on public.%I for each row execute function public.set_updated_at()',r.table_name,r.table_name);end loop;end$$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.profiles(id,full_name) values(new.id,coalesce(new.raw_user_meta_data->>'full_name',''));return new;end;$$;
create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
create or replace function public.is_app_admin() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.profiles where id=auth.uid() and role in('owner','admin'));$$;
create or replace function public.is_org_member(target uuid) returns boolean language sql stable security definer set search_path=public as $$select public.is_app_admin() or exists(select 1 from public.organization_members where organization_id=target and user_id=auth.uid());$$;
create or replace function public.is_project_member(target uuid) returns boolean language sql stable security definer set search_path=public as $$select public.is_app_admin() or exists(select 1 from public.project_members where project_id=target and user_id=auth.uid());$$;
create or replace function public.protect_profile_role() returns trigger language plpgsql security definer set search_path=public as $$begin if new.role is distinct from old.role and not public.is_app_admin() then raise exception 'Only an owner or admin can change roles';end if;return new;end;$$;
create trigger profiles_protect_role before update on public.profiles for each row execute function public.protect_profile_role();

alter table public.profiles enable row level security;alter table public.organizations enable row level security;alter table public.organization_members enable row level security;alter table public.leads enable row level security;alter table public.lead_activities enable row level security;alter table public.projects enable row level security;alter table public.project_members enable row level security;alter table public.project_phases enable row level security;alter table public.milestones enable row level security;alter table public.tasks enable row level security;alter table public.files enable row level security;alter table public.messages enable row level security;alter table public.approvals enable row level security;alter table public.proposals enable row level security;alter table public.proposal_items enable row level security;alter table public.invoices enable row level security;alter table public.payments enable row level security;alter table public.notifications enable row level security;alter table public.services enable row level security;alter table public.case_studies enable row level security;alter table public.testimonials enable row level security;alter table public.blog_posts enable row level security;alter table public.activity_logs enable row level security;

create policy profiles_read on public.profiles for select using(id=auth.uid() or public.is_app_admin());
create policy profiles_update on public.profiles for update using(id=auth.uid() or public.is_app_admin()) with check(id=auth.uid() or public.is_app_admin());
create policy org_read on public.organizations for select using(public.is_org_member(id));create policy org_admin on public.organizations for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy org_members_read on public.organization_members for select using(public.is_org_member(organization_id));create policy org_members_admin on public.organization_members for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy leads_admin on public.leads for all using(public.is_app_admin()) with check(public.is_app_admin());create policy lead_activity_admin on public.lead_activities for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy projects_read on public.projects for select using(public.is_project_member(id) or (organization_id is not null and public.is_org_member(organization_id)));create policy projects_admin on public.projects for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy project_members_read on public.project_members for select using(public.is_project_member(project_id));create policy project_members_admin on public.project_members for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy phases_read on public.project_phases for select using(public.is_project_member(project_id));create policy phases_admin on public.project_phases for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy milestones_read on public.milestones for select using(public.is_project_member(project_id));create policy milestones_admin on public.milestones for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy tasks_read on public.tasks for select using(public.is_project_member(project_id) and (client_visible or public.is_app_admin()));create policy tasks_admin on public.tasks for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy files_read on public.files for select using((project_id is not null and public.is_project_member(project_id)) or (organization_id is not null and public.is_org_member(organization_id)));create policy files_insert on public.files for insert with check(uploaded_by=auth.uid() and ((project_id is not null and public.is_project_member(project_id)) or (organization_id is not null and public.is_org_member(organization_id))));create policy files_delete on public.files for delete using(uploaded_by=auth.uid() or public.is_app_admin());
create policy messages_read on public.messages for select using(public.is_project_member(project_id));create policy messages_insert on public.messages for insert with check(sender_id=auth.uid() and public.is_project_member(project_id));create policy messages_update on public.messages for update using(sender_id=auth.uid() or public.is_app_admin()) with check(sender_id=auth.uid() or public.is_app_admin());
create policy approvals_read on public.approvals for select using(public.is_project_member(project_id));create policy approvals_insert on public.approvals for insert with check(public.is_app_admin());create policy approvals_update on public.approvals for update using(public.is_project_member(project_id)) with check(public.is_project_member(project_id));
create policy proposals_read on public.proposals for select using(public.is_app_admin() or (organization_id is not null and public.is_org_member(organization_id)));create policy proposals_admin on public.proposals for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy proposal_items_read on public.proposal_items for select using(exists(select 1 from public.proposals p where p.id=proposal_id and (public.is_app_admin() or (p.organization_id is not null and public.is_org_member(p.organization_id)))));create policy proposal_items_admin on public.proposal_items for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy invoices_read on public.invoices for select using(public.is_app_admin() or (organization_id is not null and public.is_org_member(organization_id)));create policy invoices_admin on public.invoices for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy payments_read on public.payments for select using(public.is_app_admin() or (project_id is not null and public.is_project_member(project_id)));create policy payments_admin on public.payments for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy notifications_read on public.notifications for select using(user_id=auth.uid());create policy notifications_update on public.notifications for update using(user_id=auth.uid()) with check(user_id=auth.uid());create policy notifications_admin on public.notifications for insert with check(public.is_app_admin());
create policy services_public on public.services for select using(published or public.is_app_admin());create policy services_admin on public.services for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy cases_public on public.case_studies for select using(published or public.is_app_admin());create policy cases_admin on public.case_studies for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy testimonials_public on public.testimonials for select using(published or public.is_app_admin());create policy testimonials_admin on public.testimonials for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy posts_public on public.blog_posts for select using(published or public.is_app_admin());create policy posts_admin on public.blog_posts for all using(public.is_app_admin()) with check(public.is_app_admin());
create policy logs_read on public.activity_logs for select using(public.is_app_admin() or (project_id is not null and public.is_project_member(project_id)) or (organization_id is not null and public.is_org_member(organization_id)));create policy logs_insert on public.activity_logs for insert with check(actor_id=auth.uid() or public.is_app_admin());

create index leads_status_idx on public.leads(status);create index leads_created_idx on public.leads(created_at desc);create index projects_org_idx on public.projects(organization_id);create index project_members_user_idx on public.project_members(user_id);create index milestones_project_idx on public.milestones(project_id);create index tasks_project_idx on public.tasks(project_id);create index files_project_idx on public.files(project_id);create index messages_project_created_idx on public.messages(project_id,created_at);create index invoices_org_idx on public.invoices(organization_id);create index notifications_user_idx on public.notifications(user_id,read_at);
insert into storage.buckets(id,name,public) values('project-files','project-files',false) on conflict(id) do nothing;
commit;
